//! FLUX DiT block parity helpers.
//!
//! These routines cover the first fail-closed boundary before exact DiT block
//! parity: FLUX latent patch tokenization must be bijective, and residual block
//! updates must preserve stream shapes before velocity prediction is admitted.

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct FluxLatentPatchSpec {
    pub channels: usize,
    pub height: usize,
    pub width: usize,
    pub patch: usize,
}

impl FluxLatentPatchSpec {
    pub fn token_count(&self) -> Result<usize, String> {
        self.validate()?;
        Ok((self.height / self.patch) * (self.width / self.patch))
    }

    pub fn token_dim(&self) -> Result<usize, String> {
        self.validate()?;
        Ok(self.channels * self.patch * self.patch)
    }

    fn validate(&self) -> Result<(), String> {
        if self.channels == 0 || self.height == 0 || self.width == 0 || self.patch == 0 {
            return Err("FLUX latent patch spec dimensions must be positive".to_string());
        }
        if !self.height.is_multiple_of(self.patch) || !self.width.is_multiple_of(self.patch) {
            return Err(format!(
                "FLUX latent dimensions {}x{} must be divisible by patch {}",
                self.height, self.width, self.patch
            ));
        }
        Ok(())
    }
}

pub fn pack_flux_latents_to_tokens(
    latents: &[f32],
    spec: FluxLatentPatchSpec,
) -> Result<Vec<f32>, String> {
    spec.validate()?;
    let expected = spec.channels * spec.height * spec.width;
    if latents.len() != expected {
        return Err(format!(
            "FLUX latent length mismatch: expected {expected}, got {}",
            latents.len()
        ));
    }
    let patch_h = spec.height / spec.patch;
    let patch_w = spec.width / spec.patch;
    let token_dim = spec.token_dim()?;
    let mut tokens = vec![0.0f32; patch_h * patch_w * token_dim];
    for py in 0..patch_h {
        for px in 0..patch_w {
            let token_base = (py * patch_w + px) * token_dim;
            for channel in 0..spec.channels {
                for dy in 0..spec.patch {
                    for dx in 0..spec.patch {
                        let latent_index = channel * spec.height * spec.width
                            + (py * spec.patch + dy) * spec.width
                            + (px * spec.patch + dx);
                        let token_index =
                            token_base + ((channel * spec.patch + dy) * spec.patch + dx);
                        tokens[token_index] = latents[latent_index];
                    }
                }
            }
        }
    }
    Ok(tokens)
}

pub fn unpack_flux_tokens_to_latents(
    tokens: &[f32],
    spec: FluxLatentPatchSpec,
) -> Result<Vec<f32>, String> {
    spec.validate()?;
    let patch_h = spec.height / spec.patch;
    let patch_w = spec.width / spec.patch;
    let token_dim = spec.token_dim()?;
    let expected = patch_h * patch_w * token_dim;
    if tokens.len() != expected {
        return Err(format!(
            "FLUX token length mismatch: expected {expected}, got {}",
            tokens.len()
        ));
    }
    let mut latents = vec![0.0f32; spec.channels * spec.height * spec.width];
    for py in 0..patch_h {
        for px in 0..patch_w {
            let token_base = (py * patch_w + px) * token_dim;
            for channel in 0..spec.channels {
                for dy in 0..spec.patch {
                    for dx in 0..spec.patch {
                        let token_index =
                            token_base + ((channel * spec.patch + dy) * spec.patch + dx);
                        let latent_index = channel * spec.height * spec.width
                            + (py * spec.patch + dy) * spec.width
                            + (px * spec.patch + dx);
                        latents[latent_index] = tokens[token_index];
                    }
                }
            }
        }
    }
    Ok(latents)
}

pub fn dit_residual_block_parity(
    image_stream: &[f32],
    text_stream: &[f32],
    image_residual: &[f32],
    text_residual: &[f32],
) -> Result<(Vec<f32>, Vec<f32>), String> {
    if image_stream.len() != image_residual.len() {
        return Err(format!(
            "DiT image residual length mismatch: {} vs {}",
            image_stream.len(),
            image_residual.len()
        ));
    }
    if text_stream.len() != text_residual.len() {
        return Err(format!(
            "DiT text residual length mismatch: {} vs {}",
            text_stream.len(),
            text_residual.len()
        ));
    }
    let image = image_stream
        .iter()
        .zip(image_residual.iter())
        .map(|(value, residual)| value + residual)
        .collect::<Vec<_>>();
    let text = text_stream
        .iter()
        .zip(text_residual.iter())
        .map(|(value, residual)| value + residual)
        .collect::<Vec<_>>();
    if image.iter().chain(text.iter()).any(|value| !value.is_finite()) {
        return Err("DiT residual parity produced non-finite values".to_string());
    }
    Ok((image, text))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn flux_latent_token_pack_is_bijective() {
        let spec = FluxLatentPatchSpec {
            channels: 2,
            height: 4,
            width: 4,
            patch: 2,
        };
        let latents = (0..32).map(|index| index as f32).collect::<Vec<_>>();
        let tokens = pack_flux_latents_to_tokens(&latents, spec).expect("pack");
        assert_eq!(tokens.len(), spec.token_count().unwrap() * spec.token_dim().unwrap());

        let roundtrip = unpack_flux_tokens_to_latents(&tokens, spec).expect("unpack");
        assert_eq!(roundtrip, latents);
    }

    #[test]
    fn dit_residual_parity_preserves_stream_shapes() {
        let image = vec![1.0, 2.0, 3.0, 4.0];
        let text = vec![5.0, 6.0];
        let (next_image, next_text) =
            dit_residual_block_parity(&image, &text, &[0.5; 4], &[-0.25; 2]).expect("parity");
        assert_eq!(next_image, vec![1.5, 2.5, 3.5, 4.5]);
        assert_eq!(next_text, vec![4.75, 5.75]);
    }

    #[test]
    fn flux_latent_token_pack_rejects_bad_patch() {
        let err = pack_flux_latents_to_tokens(
            &[0.0; 15],
            FluxLatentPatchSpec {
                channels: 1,
                height: 3,
                width: 5,
                patch: 2,
            },
        )
        .unwrap_err();
        assert!(err.contains("must be divisible"));
    }
}
